parameters.jsCode:
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const items = $input.all();
const inactive = [];

for (const item of items) {
  const lastEmailed = item.json.lastEmailedAt ? new Date(item.json.lastEmailedAt) : null;
  const subscribedAt = item.json.subscribedAt ? new Date(item.json.subscribedAt) : null;
  const emailSequenceStep = item.json.emailSequenceStep || 0;

  const lastEmailOld = lastEmailed && lastEmailed < sevenDaysAgo;
  const neverEngaged = subscribedAt && subscribedAt < sevenDaysAgo && emailSequenceStep === 0;

  if (lastEmailOld || neverEngaged) {
    inactive.push(item);
  }
}

return inactive;
